<!DOCTYPE html>
<html lang="pt">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>AlphaSolutions</title>
  <link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Inter:wght@300;400;500&display=swap" rel="stylesheet">
  <style>
    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    :root {
      --blue-deep: #07111f;
      --blue-dark: #0d1f3c;
      --blue-mid: #1a3a6e;
      --blue-bright: #1565c0;
      --blue-accent: #1e88e5;
      --blue-light: #42a5f5;
      --blue-glow: #64b5f6;
      --white: #ffffff;
      --silver: #b0c4de;
    }
    body { background: var(--blue-deep); min-height: 100vh; overflow: hidden; font-family: "Inter", sans-serif; }

    #particles-canvas { position: fixed; inset: 0; z-index: 0; pointer-events: none; }

    .grid-overlay {
      position: fixed; inset: 0; z-index: 1; pointer-events: none;
      background-image: linear-gradient(rgba(30,136,229,0.04) 1px, transparent 1px), linear-gradient(90deg, rgba(30,136,229,0.04) 1px, transparent 1px);
      background-size: 60px 60px;
      animation: gridFade 3s ease forwards; opacity: 0;
    }
    @keyframes gridFade { 0% { opacity:0 } 100% { opacity:1 } }

    .glow-center {
      position: fixed; inset: 0; z-index: 2; pointer-events: none;
      background: radial-gradient(ellipse 70% 60% at 50% 45%, rgba(21,101,192,0.22) 0%, transparent 70%);
      animation: glowPulse 4s ease-in-out infinite;
    }
    @keyframes glowPulse { 0%,100% { opacity:0.8; transform:scale(1); } 50% { opacity:1; transform:scale(1.05); } }

    #splash { position: fixed; inset: 0; z-index: 10; display: flex; flex-direction: column; align-items: center; justify-content: center; }

    .logo-wrap {
      position: relative; display: flex; align-items: center; justify-content: center;
      margin-bottom: 24px;
      animation: logoReveal 1.2s cubic-bezier(0.22,1,0.36,1) 0.3s both;
    }
    @keyframes logoReveal {
      from { opacity:0; transform: translateY(30px) scale(0.92); filter: blur(8px); }
      to   { opacity:1; transform: translateY(0) scale(1); filter: blur(0); }
    }
    .logo-ring {
      position: absolute; border-radius: 50%;
      border: 1px solid rgba(100,181,246,0.14);
      width: 290px; height: 290px;
      animation: ringExpand 2.5s ease-out 0.5s both;
    }
    .logo-ring:nth-child(2) { width: 350px; height: 350px; border-color: rgba(100,181,246,0.06); animation-delay: 0.8s; }
    .logo-ring:nth-child(3) { width: 410px; height: 410px; border-color: rgba(100,181,246,0.03); animation-delay: 1.1s; }
    @keyframes ringExpand { from { opacity:0; transform:scale(0.5); } to { opacity:1; transform:scale(1); } }

    .logo-img {
      position: relative; width: 210px; height: auto; z-index: 2;
      filter: drop-shadow(0 0 36px rgba(30,136,229,0.6)) drop-shadow(0 0 14px rgba(100,181,246,0.35));
      animation: logoFloat 6s ease-in-out infinite 1.5s;
    }
    @keyframes logoFloat { 0%,100% { transform:translateY(0); } 50% { transform:translateY(-9px); } }

    .tagline {
      font-family: "Rajdhani", sans-serif; font-size: 12px; font-weight: 500;
      letter-spacing: 6px; text-transform: uppercase; color: var(--silver);
      margin-bottom: 40px;
      animation: fadeUp 0.8s ease 1.3s both;
    }
    @keyframes fadeUp { from { opacity:0; transform:translateY(12px); } to { opacity:1; transform:translateY(0); } }

    .divider {
      width: 0; height: 1px; margin-bottom: 40px;
      background: linear-gradient(90deg, transparent, var(--blue-accent), var(--blue-glow), var(--blue-accent), transparent);
      animation: expandLine 1s ease 1.5s both;
    }
    @keyframes expandLine { from { width:0; opacity:0; } to { width:280px; opacity:1; } }

    .loading-track {
      width: 280px; height: 2px; background: rgba(255,255,255,0.06); border-radius: 99px; overflow: hidden;
      margin-bottom: 14px; animation: fadeUp 0.5s ease 1.7s both;
    }
    .loading-fill {
      height: 100%; width: 0%; border-radius: 99px;
      background: linear-gradient(90deg, var(--blue-bright), var(--blue-glow));
      box-shadow: 0 0 12px rgba(100,181,246,0.7);
      animation: loadFill 2.2s cubic-bezier(0.4,0,0.2,1) 1.9s forwards;
    }
    @keyframes loadFill { 0% { width:0%; } 60% { width:72%; } 85% { width:91%; } 100% { width:100%; } }

    .loading-text {
      font-size: 10px; font-weight: 300; letter-spacing: 3px; text-transform: uppercase;
      color: rgba(176,196,222,0.45); margin-bottom: 52px;
      animation: fadeUp 0.5s ease 1.7s both;
    }

    .btn-enter {
      position: relative; display: inline-flex; align-items: center; gap: 12px;
      padding: 15px 50px; background: transparent; border: none; cursor: pointer;
      font-family: "Rajdhani", sans-serif; font-size: 15px; font-weight: 700;
      letter-spacing: 5px; text-transform: uppercase; color: var(--white);
      text-decoration: none; opacity: 0;
      animation: btnAppear 0.8s ease 4.2s forwards;
      transition: transform 0.3s ease;
    }
    @keyframes btnAppear { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:translateY(0); } }
    .btn-enter:hover { transform: translateY(-3px); }

    .btn-bg {
      position: absolute; inset: 0; border-radius: 4px;
      background: linear-gradient(135deg, var(--blue-bright) 0%, var(--blue-mid) 100%);
      border: 1px solid rgba(100,181,246,0.28);
      transition: all 0.4s ease; overflow: hidden;
    }
    .btn-bg::before {
      content:""; position:absolute; inset:0;
      background: linear-gradient(135deg, var(--blue-accent), var(--blue-glow));
      opacity:0; transition: opacity 0.4s ease;
    }
    .btn-enter:hover .btn-bg::before { opacity:1; }
    .btn-bg::after {
      content:""; position:absolute; top:-50%; left:-60%;
      width:40%; height:200%; background:rgba(255,255,255,0.09);
      transform:skewX(-20deg); transition: left 0.6s ease;
    }
    .btn-enter:hover .btn-bg::after { left:140%; }

    .btn-glow {
      position:absolute; inset:-1px; border-radius:5px;
      box-shadow: 0 0 0 0 rgba(30,136,229,0);
      transition: box-shadow 0.4s ease;
    }
    .btn-enter:hover .btn-glow {
      box-shadow: 0 0 22px 5px rgba(30,136,229,0.38), 0 10px 36px rgba(30,136,229,0.22);
    }

    .btn-text { position:relative; z-index:2; }
    .btn-arrow { position:relative; z-index:2; display:flex; align-items:center; transition: transform 0.3s ease; }
    .btn-enter:hover .btn-arrow { transform: translateX(5px); }

    .corner { position:fixed; width:48px; height:48px; z-index:5; opacity:0; animation: cornerFade 1s ease 2.4s forwards; }
    @keyframes cornerFade { to { opacity:0.3; } }
    .corner-tl { top:26px; left:26px; border-top:1px solid var(--blue-accent); border-left:1px solid var(--blue-accent); }
    .corner-tr { top:26px; right:26px; border-top:1px solid var(--blue-accent); border-right:1px solid var(--blue-accent); }
    .corner-bl { bottom:26px; left:26px; border-bottom:1px solid var(--blue-accent); border-left:1px solid var(--blue-accent); }
    .corner-br { bottom:26px; right:26px; border-bottom:1px solid var(--blue-accent); border-right:1px solid var(--blue-accent); }

    .page-transition { position:fixed; inset:0; z-index:100; background:var(--blue-deep); pointer-events:none; opacity:0; }
    .page-transition.active { pointer-events:all; animation: pageOut 0.6s ease forwards; }
    @keyframes pageOut { 0% { opacity:0; } 50% { opacity:1; } 100% { opacity:1; } }
  </style>
</head>
<body>

<canvas id="particles-canvas"></canvas>
<div class="grid-overlay"></div>
<div class="glow-center"></div>

<div class="corner corner-tl"></div>
<div class="corner corner-tr"></div>
<div class="corner corner-bl"></div>
<div class="corner corner-br"></div>

<div id="splash">
  <div class="logo-wrap">
    <div class="logo-ring"></div>
    <div class="logo-ring"></div>
    <div class="logo-ring"></div>
    <img class="logo-img" src="data:image/jpeg;base64," alt="AlphaSolutions">
  </div>
  <div class="tagline">Eletr&#244;nicos &middot; Hardware &middot; Tools</div>
  <div class="divider"></div>
  <div class="loading-track"><div class="loading-fill"></div></div>
  <div class="loading-text">Departamento de Vendas</div>
<a class="btn-enter" href="acesso.php" id="enterBtn">
  <div class="btn-bg"></div>
    <div class="btn-glow"></div>
    <span class="btn-text">Entrar</span>
    <span class="btn-arrow">
      <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
        <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
      </svg>
    </span>
  </a>
</div>

<div class="page-transition" id="pageTransition"></div>

<script>
const canvas = document.getElementById("particles-canvas");
const ctx = canvas.getContext("2d");
function resize() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
resize();
window.addEventListener("resize", resize);

const particles = [];
for (let i = 0; i < 55; i++) {
  particles.push({
    x: Math.random() * window.innerWidth,
    y: Math.random() * window.innerHeight,
    r: Math.random() * 1.6 + 0.3,
    vx: (Math.random() - 0.5) * 0.35,
    vy: (Math.random() - 0.5) * 0.35,
    alpha: Math.random() * 0.45 + 0.1
  });
}
function draw() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  for (let i = 0; i < particles.length; i++) {
    for (let j = i+1; j < particles.length; j++) {
      const dx = particles[i].x - particles[j].x;
      const dy = particles[i].y - particles[j].y;
      const d = Math.sqrt(dx*dx + dy*dy);
      if (d < 130) {
        ctx.beginPath();
        ctx.strokeStyle = "rgba(30,136,229," + (0.12 * (1 - d/130)) + ")";
        ctx.lineWidth = 0.5;
        ctx.moveTo(particles[i].x, particles[i].y);
        ctx.lineTo(particles[j].x, particles[j].y);
        ctx.stroke();
      }
    }
  }
  particles.forEach(p => {
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
    ctx.fillStyle = "rgba(100,181,246," + p.alpha + ")";
    ctx.fill();
    p.x += p.vx; p.y += p.vy;
    if (p.x < -10) p.x = canvas.width + 10;
    if (p.x > canvas.width + 10) p.x = -10;
    if (p.y < -10) p.y = canvas.height + 10;
    if (p.y > canvas.height + 10) p.y = -10;
  });
  requestAnimationFrame(draw);
}
draw();

document.getElementById("enterBtn").addEventListener("click", function(e) {
  e.preventDefault();
  const dest = this.getAttribute("href");
  document.getElementById("pageTransition").classList.add("active");
  setTimeout(() => { window.location.href = dest; }, 550);
});
</script>
</body>
</html>